import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { CheckCircle, Cancel } from '@mui/icons-material';
import response from './response.json';

interface Habit {
  name: string;
  completed: boolean;
  streak: number;
}

interface HabitData {
  todayHabits: Habit[];
}

export default function Widget() {
  const habitData = response.data as HabitData;
  const { todayHabits } = habitData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1A1A1A' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: '#76FF03', fontWeight: 600 }}>
            Today's Habits
          </Typography>
          <Stack spacing={1}>
            {todayHabits.map((habit, index) => (
              <Box key={index} sx={{ display: 'flex', alignItems: 'center' }}>
                {habit.completed ? (
                  <CheckCircle sx={{ color: '#76FF03', mr: 1 }} />
                ) : (
                  <Cancel sx={{ color: '#FF1744', mr: 1 }} />
                )}
                <Typography variant="body2" sx={{ color: '#E0E0E0', flexGrow: 1 }}>
                  {habit.name}
                </Typography>
                <Chip
                  label={`Streak: ${habit.streak}`}
                  sx={{ bgcolor: '#333', color: '#E0E0E0', fontSize: '11px' }}
                />
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
